+  /** Normalize orderBy and turn a cursor into a lexicographic MikroORM filter. */
+  private getKeysetPagination(opts: CrudOptions) {
+    const cursor = opts.cursor;
+    delete opts.cursor;
+
+    if (cursor && !opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (cursor && opts.offset !== undefined) {
+      throw new BadRequestException('cursor cannot be used with offset');
+    }
+    if (!opts.orderBy || !opts.limit) {
+      return undefined;
+    }
+
+    const sort = this.normalizeCursorSort(opts.orderBy);
+    const orderBy = sort.reduce((result, { field, direction }) => {
+      result[field] = direction;
+      return result;
+    }, {} as Record<string, 'asc' | 'desc'>);
+
+    if (!cursor) {
+      return { sort, orderBy, values: undefined };
+    }
+
+    let values: Record<string, any>;
+    try {
+      const decoded = Buffer.from(cursor, 'base64').toString('utf8');
+      // Buffer accepts malformed base64, so require its canonical encoding too.
+      if (Buffer.from(decoded, 'utf8').toString('base64') !== cursor) {
+        throw new Error('Invalid base64');
+      }
+      values = JSON.parse(decoded);
+    } catch (_) {
+      throw new BadRequestException('cursor must be Base64-encoded JSON');
+    }
+
+    if (!values || Array.isArray(values) || typeof values !== 'object') {
+      throw new BadRequestException('cursor must contain a JSON object');
+    }
+    if (!Object.prototype.hasOwnProperty.call(values, this.crudConfig.id_field)) {
+      throw new BadRequestException(
+        `cursor is missing ${this.crudConfig.id_field}`,
+      );
+    }
+    for (const { field } of sort) {
+      if (!Object.prototype.hasOwnProperty.call(values, field)) {
+        throw new BadRequestException(`cursor is missing ${field}`);
+      }
+    }
+    if (values.__sort !== this.serializeCursorSort(sort)) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    return { sort, orderBy, values };
+  }
+
+  private normalizeCursorSort(orderBy: any) {
+    const orderByItems = Array.isArray(orderBy) ? orderBy : [orderBy];
+    const sort: { field: string; direction: 'asc' | 'desc' }[] = [];
+    for (const item of orderByItems) {
+      for (const [field, value] of Object.entries(item || {})) {
+        const direction = String(value).toLowerCase().startsWith('desc')
+          ? 'desc'
+          : 'asc';
+        sort.push({ field, direction });
+      }
+    }
+    const idField = this.crudConfig.id_field;
+    if (!sort.some(({ field }) => field === idField)) {
+      sort.push({ field: idField, direction: 'asc' });
+    }
+    return sort;
+  }
+
+  private addKeysetFilter(entity: Partial<T>, keyset: any): Partial<T> {
+    if (!keyset.values) {
+      return entity;
+    }
+    const alternatives = keyset.sort.map((entry, index) => {
+      const equalFields = keyset.sort.slice(0, index).reduce((result, prior) => {
+        result[prior.field] = keyset.values[prior.field];
+        return result;
+      }, {});
+      return {
+        ...equalFields,
+        [entry.field]: {
+          [entry.direction === 'asc' ? '$gt' : '$lt']:
+            keyset.values[entry.field],
+        },
+      };
+    });
+    return { $and: [entity, { $or: alternatives }] } as Partial<T>;
+  }
+
+  private createCursor(entity: T, sort: { field: string; direction: string }[]) {
+    const payload: Record<string, any> = {};
+    for (const { field } of sort) {
+      payload[field] = entity[field];
+    }
+    payload.__sort = this.serializeCursorSort(sort);
+    return Buffer.from(JSON.stringify(payload)).toString('base64');
+  }
+
+  private serializeCursorSort(sort: { field: string; direction: string }[]) {
+    return sort.map(({ field, direction }) => `${field}:${direction}`).join(',');
+  }
